let scheduler = null;

export function initCaptivateServiceHandler(onReadyCallback) {
  if (window.ServiceHandler && typeof window.ServiceHandler.init === 'function') {
    window.ServiceHandler.init();

    window.ServiceHandler.onready = function () {
      scheduler = window.ServiceHandler.scheduler;
      console.info('ServiceHandler connected, ready to send/receive messages!');
      if (typeof onReadyCallback === 'function') {
        onReadyCallback(scheduler);
      }
    };

    window.ServiceHandler.onclose = function () {
      console.warn('ServiceHandler disconnected');
    };

    window.ServiceHandler.onerror = function (error) {
      console.error('ServiceHandler error', error);
    };
  } else {
    console.warn('ServiceHandler not available on window.');
  }
}

export function sendVariablesToCaptivate(variables) {
  if (scheduler && typeof scheduler.scheduleVariablesEx === 'function') {
    // Use the inputBehavior name from your XML
    const INPUT_NAME = "VeeFriends: Game Manager";
    scheduler.scheduleVariablesEx(
      "update", 0.0, INPUT_NAME, "", INPUT_NAME, "", "", "", variables
    );
    console.log('Sent variables to Captivate:', variables);
  } else {
    console.warn('Scheduler not ready or scheduleVariablesEx not available.');
  }
}
